@startuml
!option handwritten true

class "Container" {
  +__contains__(item)
}

class "Iterable" {
  +__iter__()
}

class "Sized" {
  +__len__(item)
}

class "Collection" {
}

class "Mapping" {
  +__getitem__(key)
  +keys()
  +items()
  +values()
  +get(key, default)
}

class "MutableMapping" {
  +__setitem__(key, value)
  +__delitem__(key)
}

class "dict" {
}

"Container" <|-- "Collection"
"Iterable" <|-- "Collection"
"Sized" <|-- "Collection"
"Collection" <|-- "Mapping"
"Mapping" <|-- "MutableMapping"
"MutableMapping" <|-- "dict"

@enduml
